import{_ as s,o as a,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const k=JSON.parse('{"title":"Qwen","description":"","frontmatter":{"read_when":["你想在 OpenSoul 中使用 Qwen","你想要免费层 OAuth 访问 Qwen Coder"],"summary":"在 OpenSoul 中使用 Qwen OAuth（免费层）","title":"Qwen","x-i18n":{"generated_at":"2026-02-03T07:53:34Z","model":"claude-opus-4-5","provider":"pi","source_hash":"88b88e224e2fecbb1ca26e24fbccdbe25609be40b38335d0451343a5da53fdd4","source_path":"providers/qwen.md","workflow":15}},"headers":[],"relativePath":"zh-CN/providers/qwen.md","filePath":"zh-CN/providers/qwen.md","lastUpdated":1771906665000}'),d={name:"zh-CN/providers/qwen.md"};function l(t,e,p,o,r,h){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="qwen" tabindex="-1"><a class="header-anchor" href="#qwen">#</a> Qwen</h1><p>Qwen 为 Qwen Coder 和 Qwen Vision 模型提供免费层 OAuth 流程（每天 2,000 次请求，受 Qwen 速率限制约束）。</p><h2 id="启用插件" tabindex="-1"><a class="header-anchor" href="#启用插件">#</a> 启用插件</h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen-portal-auth</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>启用后重启 Gateway 网关。</p><h2 id="认证" tabindex="-1"><a class="header-anchor" href="#认证">#</a> 认证</h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen-portal</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set-default</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这会运行 Qwen 设备码 OAuth 流程并将提供商条目写入你的 <code>models.json</code>（加上一个 <code>qwen</code> 别名以便快速切换）。</p><h2 id="模型-id" tabindex="-1"><a class="header-anchor" href="#模型-id">#</a> 模型 ID</h2><ul><li><code>qwen-portal/coder-model</code></li><li><code>qwen-portal/vision-model</code></li></ul><p>切换模型：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen-portal/coder-model</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="复用-qwen-code-cli-登录" tabindex="-1"><a class="header-anchor" href="#复用-qwen-code-cli-登录">#</a> 复用 Qwen Code CLI 登录</h2><p>如果你已经使用 Qwen Code CLI 登录，OpenSoul 会在加载认证存储时从 <code>~/.qwen/oauth_creds.json</code> 同步凭证。你仍然需要一个 <code>models.providers.qwen-portal</code> 条目（使用上面的登录命令创建一个）。</p><h2 id="注意" tabindex="-1"><a class="header-anchor" href="#注意">#</a> 注意</h2><ul><li>令牌自动刷新；如果刷新失败或访问被撤销，请重新运行登录命令。</li><li>默认基础 URL：<code>https://portal.qwen.ai/v1</code>（如果 Qwen 提供不同的端点，使用 <code>models.providers.qwen-portal.baseUrl</code> 覆盖）。</li><li>参阅<a href="/docs/concepts/model-providers">模型提供商</a>了解提供商级别的规则。</li></ul>',16)])])}const u=s(d,[["render",l]]);export{k as __pageData,u as default};
